def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0 + (capacity * 7) - (usage_ratio * 85)
        if capacity > 10:
            priority += np.sqrt(capacity) * 12
        else:
            priority -= (10 - capacity) ** 1.5
        if usage_ratio > 3:
            priority += 4500 * np.power(usage_ratio, 1.25)
            if capacity % 2 == 0:
                priority += 100 * np.sin(capacity)
            else:
                priority -= 50 * np.cos(usage_ratio * np.pi)
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2800 * delta ** 2
            for q in range(1, 7):
                priority += ((-1) ** (q+1)) * np.cos(usage_ratio * np.pi * q) * 15 / (q+1)
        elif 1 < usage_ratio <= 2:
            try:
                log_val = np.log1p(usage_ratio - 1 + 1e-16)
                priority += (log_val)**3 * 22
            except FloatingPointError:
                priority += 200
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.4:
                    priority += power * 18 / j
                    if j % 2 == 1:
                        priority += 3 * j
                else:
                    priority += (1 - power) * 12 / (j + 2)
                    if j == 7 and usage_ratio > 1.7:
                        priority += 10
            if capacity % 2.7 < 0.5:
                priority += 30 * np.sin(capacity * 5)
        elif 0.3 < usage_ratio <= 1:
            priority += 120 * (1 - usage_ratio) + capacity * 5
            for x in range(1, 8):
                ratio_pow = usage_ratio ** x
                priority += (np.tan(ratio_pow * np.pi / 3) - 0.3) * 12 / x
                if usage_ratio < 0.12 * x:
                    priority -= 7 * x
            if capacity < 0.1:
                priority += np.sqrt(capacity) * 250
            elif capacity < 1:
                priority += np.log1p(capacity * 20) * 35
            else:
                priority += (capacity % 4) * 20
        else:
            priority += 150 * (1 - usage_ratio) + capacity * 10
            for y in range(1, 10):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 2) - 0.5) * 20 / y
                if usage_ratio < 0.05 * y:
                    priority -= 10 * y
            if capacity < 0.05:
                priority += np.sqrt(capacity) * 300
            elif capacity < 0.3:
                priority += np.log1p(capacity * 30) * 40
            else:
                priority += (capacity % 5) * 25
        if capacity < 0.15:
            priority += 55
            if usage_ratio > 0.85:
                priority += 65
            elif usage_ratio < 0.2:
                priority -= 35
                for r in range(1, 6):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1:
            priority += 25
            if usage_ratio > 0.9:
                priority += 50
            elif usage_ratio < 0.35:
                priority -= 20
        else:
            if usage_ratio < 0.25:
                priority -= 30
            elif usage_ratio > 0.99:
                priority += 75
            else:
                priority += 20
        proximity_score = 0
        if int(capacity * 2000) % 17 == 0:
            proximity_score += 15
        if int(capacity * 400) % 13 == 0:
            proximity_score -= 10
        if int(capacity * 110) % 6 == 0:
            proximity_score += 12
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 8)
            if diff < 0.025:
                proximity_score += 20 / k
            elif diff < 0.06:
                proximity_score += 10 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = int(capacity * 1200) % (m + 7)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = int(usage_ratio * 1500) % (n + 4)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 2:
                proximity_score -= 5 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 7):
                priority -= s * 6
        elif usage_ratio > 0.99:
            for t in range(1, 7):
                priority += t * 8
        if capacity > 2:
            if capacity % 1 < 0.07:
                priority += 30
            if (int(capacity * 2000) % 19 == 0) and (usage_ratio > 0.7):
                priority += 50
            if capacity % 0.5 < 0.05 and usage_ratio < 0.5:
                priority -= 20
            for p in range(1, 5):
                if (int(capacity * 100) % (p + 2) == 0) and (usage_ratio > p/10):
                    priority += 10 * p
                else:
                    priority -= 5 * p
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
